    const res = await request(app).post("/auth/login").send({
      username: "logintest",
      password: "wrongpassword",
    });
    expect(res.status).toBe(401);
  });

  it("POST /auth/login should return 401 for non-existent user", async () => {
    const res = await request(app).post("/auth/login").send({
      username: "nonexistent",
      password: "whatever",
